mapper.select:
SELECT user_id AS userId, user_name AS userName, real_name AS realName, user_type AS userType, student_no AS studentNo, teacher_no AS teacherNo, college_id AS collegeId, major_id AS majorId, user_avatar AS userAvatar, user_phone AS userPhone, user_email AS userEmail, status, create_time AS createTime, update_time AS updateTime FROM sys_user WHERE is_deleted = 0
AND (user_name LIKE CONCAT('%', #{keyword}, '%') OR real_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY user_id DESC LIMIT #{offset}, #{limit}
